package org.apache.commons.csv;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVParser;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    private CSVFormat csvFormat;
    private Reader mockReader;

    @BeforeEach
    public void setUp() {
        csvFormat = CSVFormat.DEFAULT;
        mockReader = mock(Reader.class);
    }

    @Test
    public void testParse_ReturnsCSVParser() throws IOException {
        CSVParser parser = csvFormat.parse(mockReader);
        assertNotNull(parser);
        // The CSVParser should have been constructed with the Reader and this CSVFormat instance
        // Since CSVParser constructor is called directly, we cannot verify internals here without mocking CSVParser.
        // But we can check that parse returns a non-null CSVParser instance.
    }

    @Test
    public void testParse_WithNullReader_ThrowsNullPointerException() {
        assertThrows(NullPointerException.class, () -> {
            csvFormat.parse(null);
        });
    }

    @Test
    public void testParse_WithCustomFormat() throws IOException {
        CSVFormat customFormat = CSVFormat.newFormat(';')
                .withQuote('\'')
                .withIgnoreEmptyLines(true)
                .withRecordSeparator("\n");
        CSVParser parser = customFormat.parse(mockReader);
        assertNotNull(parser);
    }
}
